import { SkillBuilders, HandlerInput, RequestHandler } from 'ask-sdk-core';
import { Response, SessionEndedRequest, IntentRequest } from 'ask-sdk-model';

/**
 * OmegA Bridge: Alexa-to-Sovereign Proxy
 * Routes Alexa intents to the OmegA Gateway API.
 */

const OMEGA_GATEWAY_URL = process.env.OMEGA_GATEWAY_URL || 'http://localhost:8787/api/v1/chat';

const LaunchRequestHandler: RequestHandler = {
    canHandle(handlerInput: HandlerInput) {
        return handlerInput.requestEnvelope.request.type === 'LaunchRequest';
    },
    handle(handlerInput: HandlerInput) {
        const speechText = 'OmegA is online. Status: AR137 Naomi. How may I assist the ONE Ecosystem today?';
        return handlerInput.responseBuilder
            .speak(speechText)
            .reprompt(speechText)
            .getResponse();
    }
};

const OmegAIntentHandler: RequestHandler = {
    canHandle(handlerInput: HandlerInput) {
        return handlerInput.requestEnvelope.request.type === 'IntentRequest' &&
            handlerInput.requestEnvelope.request.intent.name === 'OmegAIntent';
    },
    async handle(handlerInput: HandlerInput) {
        const intentRequest = handlerInput.requestEnvelope.request as IntentRequest;
        const userInput = intentRequest.intent.slots?.query?.value || '';

        try {
            // Forward to OmegA Gateway
            const response = await fetch(OMEGA_GATEWAY_URL, {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ message: userInput })
            });

            const data = await response.json();
            const output = data.response || 'System nominal.';

            return handlerInput.responseBuilder
                .speak(output)
                .getResponse();
        } catch (error) {
            console.error('Bridge Error:', error);
            return handlerInput.responseBuilder
                .speak('Bridge link unstable. Verify OmegA Gateway status.')
                .getResponse();
        }
    }
};

export const handler = SkillBuilders.custom()
    .addRequestHandlers(
        LaunchRequestHandler,
        OmegAIntentHandler
    )
    .lambda();

