.orbWrap {
  position: relative;
  display: flex;
  align-items: center;
  justify-content: center;
  flex-shrink: 0;
  cursor: pointer;
  user-select: none;
}

.canvas {
  position: absolute;
  inset: 0;
  width: 100%;
  height: 100%;
}

.symbol {
  position: relative;
  z-index: 2;
  font-family: 'Orbitron', monospace;
  font-size: clamp(3rem, 8vw, 5.5rem);
  font-weight: 900;
  letter-spacing: -0.02em;
  transition: color 0.6s ease, text-shadow 0.6s ease, transform 0.4s var(--ease-snappy);
  pointer-events: none;
}

/* ── State colours ─────────────────────────────────────────────────── */

.dormant .symbol {
  color: rgba(99, 102, 241, 0.45);
  text-shadow:
    0 0 20px rgba(99, 102, 241, 0.3),
    0 0 60px rgba(99, 102, 241, 0.08);
}

.listening .symbol {
  color: rgba(180, 160, 255, 0.95);
  text-shadow:
    0 0 28px rgba(139, 92, 246, 0.9),
    0 0 70px rgba(99, 102, 241, 0.45),
    0 0 120px rgba(99, 102, 241, 0.15);
  animation: orb-listen 2.4s ease-in-out infinite;
}

.thinking .symbol {
  color: rgba(228, 184, 74, 0.95);
  text-shadow:
    0 0 28px rgba(228, 184, 74, 0.9),
    0 0 80px rgba(228, 184, 74, 0.4),
    0 0 140px rgba(228, 184, 74, 0.15);
  animation: orb-think 1.8s ease-in-out infinite;
}

.speaking .symbol {
  color: rgba(220, 205, 255, 0.98);
  text-shadow:
    0 0 32px rgba(196, 181, 253, 0.95),
    0 0 90px rgba(139, 92, 246, 0.5),
    0 0 160px rgba(99, 102, 241, 0.2);
  animation: orb-speak 1.2s ease-in-out infinite;
}

.followup .symbol {
  color: rgba(99, 210, 190, 0.9);
  text-shadow:
    0 0 24px rgba(99, 210, 190, 0.8),
    0 0 60px rgba(16, 185, 129, 0.3);
  animation: orb-followup 3s ease-in-out infinite;
}

/* ── Animations ────────────────────────────────────────────────────── */

@keyframes orb-listen {
  0%, 100% { transform: scale(1); }
  50%       { transform: scale(1.04); }
}

@keyframes orb-think {
  0%   { transform: scale(1) rotate(0deg); }
  25%  { transform: scale(1.06) rotate(1.5deg); }
  75%  { transform: scale(1.06) rotate(-1.5deg); }
  100% { transform: scale(1) rotate(0deg); }
}

@keyframes orb-speak {
  0%, 100% { transform: scale(1); }
  50%       { transform: scale(1.03); }
}

@keyframes orb-followup {
  0%, 100% { transform: scale(1); opacity: 0.9; }
  50%       { transform: scale(1.02); opacity: 1; }
}

