'use client';

import { useState, useRef, useEffect, useCallback } from 'react';
import dynamic from 'next/dynamic';
import { chatStream } from '@/lib/api';
import { useVoiceEngine } from '@/hooks/useVoiceEngine';
import Sidebar from '@/components/Sidebar/Sidebar';
import s from './page.module.css';

const VoiceOrb = dynamic(() => import('@/components/VoiceOrb/VoiceOrb'), { ssr: false });

interface Msg {
  role: 'user' | 'omega';
  text: string;
  timestamp?: string;
  provider?: string;
}

const STATE_LABELS: Record<string, string> = {
  dormant:  'Say "Mega" to wake',
  listening: 'Listening...',
  thinking:  'Thinking...',
  speaking:  'Speaking...',
  followup:  'I\'m here — go ahead',
};

export default function Home() {
  const [messages, setMessages] = useState<Msg[]>([]);
  const [error, setError] = useState<string | null>(null);
  const [sessionId, setSessionId] = useState<string | null>(null);
  const [sessionList, setSessionList] = useState<{ id: string; created_at: string; preview: string }[]>([]);
  const [sidebarOpen, setSidebarOpen] = useState(false);
  const [provider, setProvider] = useState<string | null>(null);
  const [textInput, setTextInput] = useState('');
  const [showTextInput, setShowTextInput] = useState(false);
  const [isProcessing, setIsProcessing] = useState(false);

  // Last omega reply for TTS
  const pendingTTS = useRef<string | null>(null);

  const feedRef = useRef<HTMLDivElement>(null);
  const inputRef = useRef<HTMLTextAreaElement>(null);

  // Load saved session
  useEffect(() => {
    const saved = localStorage.getItem('omega_session');
    if (saved) setSessionId(saved);
  }, []);

  const refreshSessions = useCallback(() => {
    fetch('/api/sessions')
      .then(r => r.json())
      .then(d => { if (Array.isArray(d)) setSessionList(d); })
      .catch(console.error);
  }, []);

  useEffect(() => { refreshSessions(); }, [refreshSessions]);

  // Auto-scroll
  useEffect(() => {
    feedRef.current?.scrollTo({ top: feedRef.current.scrollHeight, behavior: 'smooth' });
  }, [messages]);

  // ── Core send ───────────────────────────────────────────────────────────────
  const sendMessage = useCallback(async (text: string) => {
    if (!text.trim() || isProcessing) return;
    setError(null);
    setIsProcessing(true);
    pendingTTS.current = null;

    const newMsg: Msg = { role: 'user', text, timestamp: new Date().toISOString() };
    const history = [...messages];
    setMessages(prev => [...prev, newMsg]);

    let fullReply = '';

    try {
      const res = await chatStream(
        { user: text, history, sessionId: sessionId ?? undefined },
        chunk => {
          fullReply += chunk;
          setMessages(prev => {
            const updated = [...prev];
            const last = updated[updated.length - 1];
            if (last.role === 'user') {
              updated.push({ role: 'omega', text: chunk, timestamp: new Date().toISOString() });
            } else {
              updated[updated.length - 1] = { ...last, text: last.text + chunk };
            }
            return updated;
          });
        },
        () => {}
      );

      if (res.sessionId && !sessionId) {
        setSessionId(res.sessionId);
        localStorage.setItem('omega_session', res.sessionId);
      }
      if (res.provider) setProvider(res.provider);

      setMessages(prev => {
        const updated = [...prev];
        const last = updated[updated.length - 1];
        if (last.role === 'omega') updated[updated.length - 1] = { ...last, provider: res.provider };
        return updated;
      });

      refreshSessions();
      pendingTTS.current = fullReply;
    } catch (err) {
      setError(err instanceof Error ? err.message : String(err));
    } finally {
      setIsProcessing(false);
    }
  }, [isProcessing, messages, sessionId, refreshSessions]);

  // ── Voice engine ────────────────────────────────────────────────────────────
  const voice = useVoiceEngine({
    onTranscript: sendMessage,
    onTTSEnd: () => { /* followup handled inside engine */ },
  });

  // Auto-TTS after every OmegA response
  useEffect(() => {
    if (!isProcessing && pendingTTS.current) {
      const text = pendingTTS.current;
      pendingTTS.current = null;
      voice.speakText(text);
    }
  }, [isProcessing, voice]);

  // ── Text input send ─────────────────────────────────────────────────────────
  const handleTextSend = useCallback(() => {
    const t = textInput.trim();
    if (!t) return;
    setTextInput('');
    sendMessage(t);
  }, [textInput, sendMessage]);

  // ── Session management ──────────────────────────────────────────────────────
  const loadSession = async (id: string) => {
    try {
      const res = await fetch(`/api/sessions/${id}`);
      const data = await res.json();
      if (Array.isArray(data)) {
        // eslint-disable-next-line @typescript-eslint/no-explicit-any
        setMessages(data.map((m: any) => ({ role: m.role, text: m.content, timestamp: m.created_at })));
        setSessionId(id);
        localStorage.setItem('omega_session', id);
        setSidebarOpen(false);
      }
    } catch (err) { console.error(err); }
  };

  const startNewChat = () => {
    setMessages([]);
    setSessionId(null);
    setProvider(null);
    localStorage.removeItem('omega_session');
    setSidebarOpen(false);
  };

  // ── Render ──────────────────────────────────────────────────────────────────
  const orbSize = typeof window !== 'undefined' && window.innerWidth < 480 ? 180 : 220;
  const stateLabel = isProcessing ? 'Thinking...' : STATE_LABELS[voice.voiceState] ?? '';

  return (
    <div className={s.root}>
      {/* ── Starfield background ── */}
      <div className={s.starfield} aria-hidden />

      {/* ── Sidebar ── */}
      <Sidebar
        sessions={sessionList}
        activeSessionId={sessionId}
        onNewChat={startNewChat}
        onSelectSession={loadSession}
        isOpen={sidebarOpen}
        onToggle={() => setSidebarOpen(o => !o)}
      />

      {/* ── Main ── */}
      <div className={`${s.main} ${sidebarOpen ? s.mainShifted : ''}`}>

        {/* Top bar */}
        <header className={s.topBar}>
          <button
            className={s.menuBtn}
            onClick={() => setSidebarOpen(o => !o)}
            aria-label="Toggle history"
          >
            <span /><span /><span />
          </button>
          <div className={s.topBrand}>
            <span className={s.topOmega}>Ω</span>
            <span className={s.topName}>OmegA</span>
          </div>
          <div className={s.topStatus}>
            {provider && <span className={s.providerBadge}>{provider.split('-')[0]}</span>}
            <span className={`${s.statusDot} ${isProcessing ? s.statusDotThinking : voice.voiceState !== 'dormant' ? s.statusDotActive : ''}`} />
          </div>
        </header>

        {/* ── Orb stage ── */}
        <div className={s.stage}>
          <div
            className={s.orbContainer}
            onClick={voice.toggle}
            title={voice.voiceState === 'dormant' ? 'Click to activate' : 'Click to mute'}
          >
            <VoiceOrb
              voiceState={voice.voiceState}
              micLevel={voice.micLevel}
              ttsLevel={voice.ttsLevel}
              thinking={isProcessing}
              size={orbSize}
            />
          </div>

          {/* State label */}
          <div className={`${s.stateLabel} ${s[`stateLabel_${voice.voiceState}`]}`}>
            {stateLabel}
          </div>

          {/* Interim transcript */}
          {voice.interim && (
            <div className={s.interimBox}>
              <span className={s.interimText}>{voice.interim}</span>
            </div>
          )}
        </div>

        {/* ── Conversation feed ── */}
        {messages.length > 0 && (
          <div className={s.feed} ref={feedRef}>
            {messages.map((msg, i) => (
              <div
                key={i}
                className={`${s.bubble} ${msg.role === 'user' ? s.bubbleUser : s.bubbleOmega}`}
              >
                {msg.role === 'omega' && <span className={s.bubblePrefix}>Ω</span>}
                <span className={s.bubbleText}>{msg.text}</span>
              </div>
            ))}
            {isProcessing && (
              <div className={`${s.bubble} ${s.bubbleOmega} ${s.bubbleThinking}`}>
                <span className={s.bubblePrefix}>Ω</span>
                <span className={s.thinkDots}>
                  <span /><span /><span />
                </span>
              </div>
            )}
            {error && <div className={s.errorBubble}>{error}</div>}
          </div>
        )}

        {/* ── Bottom bar ── */}
        <div className={s.bottomBar}>
          {showTextInput ? (
            <div className={s.textInputRow}>
              <textarea
                ref={inputRef}
                className={s.textInput}
                value={textInput}
                onChange={e => setTextInput(e.target.value)}
                onKeyDown={e => {
                  if (e.key === 'Enter' && !e.shiftKey) { e.preventDefault(); handleTextSend(); }
                }}
                placeholder="Type a message..."
                rows={1}
                autoFocus
              />
              <button
                className={s.sendBtn}
                onClick={handleTextSend}
                disabled={!textInput.trim() || isProcessing}
                aria-label="Send"
              >
                ›
              </button>
              <button
                className={s.closeTextBtn}
                onClick={() => setShowTextInput(false)}
                aria-label="Close text input"
              >
                ✕
              </button>
            </div>
          ) : (
            <div className={s.bottomActions}>
              <button
                className={s.typeBtn}
                onClick={() => setShowTextInput(true)}
                aria-label="Type instead"
              >
                <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
                  <path d="M11 4H4a2 2 0 0 0-2 2v14a2 2 0 0 0 2 2h14a2 2 0 0 0 2-2v-7"/>
                  <path d="M18.5 2.5a2.121 2.121 0 0 1 3 3L12 15l-4 1 1-4 9.5-9.5z"/>
                </svg>
                Type
              </button>

              {!voice.supported && (
                <span className={s.noVoiceNote}>Voice not supported in this browser</span>
              )}

              <button
                className={`${s.micBtn} ${voice.voiceState !== 'dormant' ? s.micBtnActive : ''}`}
                onClick={voice.toggle}
                aria-label={voice.voiceState === 'dormant' ? 'Activate voice' : 'Mute voice'}
              >
                {voice.voiceState === 'dormant' ? (
                  <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
                    <line x1="1" y1="1" x2="23" y2="23"/>
                    <path d="M9 9v3a3 3 0 0 0 5.12 2.12M15 9.34V4a3 3 0 0 0-5.94-.6"/>
                    <path d="M17 16.95A7 7 0 0 1 5 12v-2m14 0v2a7 7 0 0 1-.11 1.23"/>
                    <line x1="12" y1="19" x2="12" y2="23"/>
                    <line x1="8" y1="23" x2="16" y2="23"/>
                  </svg>
                ) : (
                  <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
                    <path d="M12 1a3 3 0 0 0-3 3v8a3 3 0 0 0 6 0V4a3 3 0 0 0-3-3z"/>
                    <path d="M19 10v2a7 7 0 0 1-14 0v-2"/>
                    <line x1="12" y1="19" x2="12" y2="23"/>
                    <line x1="8" y1="23" x2="16" y2="23"/>
                  </svg>
                )}
              </button>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

