/* ── App Layout — Sidebar + Main ────────────────────────────────── */
.appLayout {
  position: fixed;
  inset: 0;
  display: flex;
  z-index: 1;
}

.mainArea {
  flex: 1;
  display: flex;
  flex-direction: column;
  min-width: 0;
  position: relative;
  height: 100%;
}

/* ── Message Feed ──────────────────────────────────────────────── */
.feed {
  flex: 1;
  overflow-y: auto;
  overflow-x: hidden;
  padding: var(--space-5) 0;
  padding-bottom: 1rem;
  display: flex;
  flex-direction: column;
  gap: var(--space-4);
  scroll-behavior: smooth;
}

/* Constrain readable width on desktop — messages own their horizontal padding */
.feed > * {
  width: 100%;
  max-width: 860px;
  margin-left: auto;
  margin-right: auto;
  box-sizing: border-box;
}

/* ── Empty State (shown when no messages) ─────────────────────── */
.emptyState {
  flex: 1;
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  gap: var(--space-4);
  user-select: none;
  pointer-events: none;
}

.emptyOmega {
  font-family: 'Orbitron', sans-serif;
  font-size: clamp(80px, 18vw, 140px);
  font-weight: 900;
  color: var(--gold);
  line-height: 1;
  animation: omega-breathe 4s ease-in-out infinite;
  will-change: filter;
}

.emptyLabel {
  font-family: 'Space Grotesk', sans-serif;
  font-size: clamp(14px, 2.5vw, 17px);
  color: var(--dim);
  letter-spacing: 0.12em;
}

/* ── Error ──────────────────────────────────────────────────────── */
.error {
  padding: var(--space-3) var(--space-4);
  background: rgba(239, 68, 68, 0.15);
  border: 1px solid rgba(239, 68, 68, 0.3);
  border-radius: 12px;
  color: #fca5a5;
  font-size: 0.88rem;
  animation: fade-up 0.3s var(--ease-snappy) both;
}

/* ── Scroll Pill ───────────────────────────────────────────────── */
.scrollPillWrap {
  position: absolute;
  bottom: 100px;
  left: 50%;
